// ============================================================

const ni = $input.item.json.normalized_input;
const senderEmail  = (ni.raw_meta && ni.raw_meta.sender_email)  || null;
const senderDomain = (ni.raw_meta && ni.raw_meta.sender_domain) ||
                     (senderEmail ? senderEmail.split('@')[1] : null);
const subject      = (ni.subject || '').toLowerCase();
const rawText      = (ni.raw_text || '').toLowerCase();

