};

// Hardcoded label IDs - no API call needed
const LABEL_ID_MAP = {
  'job/interview': 'Label_3522530513145419602',
  'job/offer':     'Label_2041686244015141831',
  'job/rejected':  'Label_2446754488129490636',
  'job/newsletter':'Label_7387780672007419096',
  'job/active':    'Label_7449061610964528383',
