};

const gmailLabel = LABEL_MAP[category] || 'job/active';
const labelId    = LABEL_ID_MAP[gmailLabel] || null;
const msgId      = $('Normalize Email').item.json.normalized_input.raw_meta.message_id || null;

return [{ json: {
  job_id:           $input.item.json.job_id,
