  job_title:        event.job_title       || null,
  salary_min:       event.salary_min      || null,
  salary_max:       event.salary_max      || null,
  salary_currency:  event.salary_currency || null
} }];

const d = $input.item.json;

// Build HTML description for Google Calendar (German labels, ASCII only)
// Fields from Map Category node: company_name, job_title, interview_date, stage, priority, gmail_label, job_id_fuzzy, salary_min, salary_max, salary_currency
const parts = [];
if (d.company_name)    parts.push('<b>Unternehmen:</b> ' + d.company_name);
if (d.job_title)       parts.push('<b>Position:</b> ' + d.job_title);
if (d.interview_date)  parts.push('<b>Datum:</b> ' + String(d.interview_date).substring(0, 10));
if (d.stage)           parts.push('<b>Phase:</b> ' + d.stage);
if (d.priority)        parts.push('<b>Prioritaet:</b> ' + d.priority);
if (d.salary_min || d.salary_max) {
  const range = [d.salary_min, d.salary_max].filter(Boolean).join('-');
  parts.push('<b>Gehalt:</b> ' + range + (d.salary_currency ? ' ' + d.salary_currency : ''));
}
if (d.gmail_label)        parts.push('<b>Label:</b> ' + d.gmail_label);
if (d.job_id_fuzzy)       parts.push('<b>ID:</b> ' + d.job_id_fuzzy);
if (d.gmail_message_id)   parts.push('<a href="https://mail.google.com/mail/u/0/#all/' + d.gmail_message_id + '">E-Mail oeffnen</a>');

return [{ json: {
  ...d,
  calendar_description: parts.join('<br>'),
  has_interview_date: !!(d.interview_date)
} }];

// Find existing "[JobRadar]" event from today's events
const items = $input.item.json.items || [];
const listEvent = items.find(e => (e.summary || '').includes('[JobRadar]'));

// Build new vacancy entry for description (German labels, ASCII only)
// Fields from Map Category node: company_name, job_title, interview_date, stage, priority, gmail_label, job_id_fuzzy
const prev = $('Format for Calendar').first().json;
const dateStr = prev.interview_date ? String(prev.interview_date).substring(0, 10) : '-';
const entry = [
  '<b>---</b>',
  '<b>' + (prev.company_name || prev.job_id_fuzzy || 'Vakanz') + '</b>',
  'Position: ' + (prev.job_title || '-'),
  'Datum: ' + dateStr,
  'Phase: ' + (prev.stage || '-'),
  'Prioritaet: ' + (prev.priority || '-'),
  'Label: ' + (prev.gmail_label || '-'),
  'ID: ' + (prev.job_id_fuzzy || '-'),
  (prev.gmail_message_id ? '<a href="https://mail.google.com/mail/u/0/#all/' + prev.gmail_message_id + '">E-Mail oeffnen</a>' : null)
].filter(Boolean).join('<br>');

const existingDesc = listEvent ? (listEvent.description || '') : '';
const newDesc = existingDesc ? existingDesc + '<br><br>' + entry : entry;

return [{ json: {
  list_event_id: listEvent ? listEvent.id : null,
  list_event_found: !!listEvent,
  new_description: newDesc
} }];

const item = $input.item.json;
const ni = item.normalized_input || {};
const riskLevel = item.sender_risk_level || 'unknown';
const riskSignals = item.sender_risk_signals || [];

return [{ json: {
  sender: (ni.raw_meta && ni.raw_meta.sender) || 'unknown',
  subject: ni.subject || '(no subject)',
  date: ni.date || null,
  email_account: ni.email_account_id || 'unknown',
  risk_level: riskLevel,
  risk_signals: riskSignals.join(', ') || 'none',
  preview: (ni.raw_text || '').substring(0, 300)
} }];

const item = $input.item.json;
const ni = item.normalized_input || {};

return [{ json: {
  sender: (ni.raw_meta && ni.raw_meta.sender) || 'unknown',
  subject: ni.subject || '(no subject)',
  date: ni.date || null,
  preview: (ni.raw_text || '').substring(0, 300)
} }];

// Filter: Skip Expired
// Drops jobs whose deadline has already passed.
// No deadline -> pass through (benefit of the doubt).
const e = $('Parse LLM Response').item.json.job_event;
const deadline = e.application_deadline || e.response_deadline || null;

if (deadline) {
  const deadlineDate = new Date(deadline);
  if (!isNaN(deadlineDate.getTime()) && deadlineDate < new Date()) {
    return []; // expired - drop
  }
}

return [$input.item];
